    position: relative; 
    overflow: hidden; /* Hide scrollbars if needed, but grid handles layout */
    box-shadow: 0 4px 6px rgba(0,0,0,0.1);
  }

  .spreadsheet-grid { 
    display: grid; 
    grid-template-columns: 30px repeat(10, 80px); 
    grid-auto-rows: 25px; 
    border-collapse: collapse; 
    font-size: 12px;
    width: 100%; height: 100%;
  }

  /* Headers */
